const body = $input.first().json.body;
const event = body;
const subscription = event?.data?.object || {};
const previousAttributes = event?.data?.previous_attributes || {};

const customerId = subscription.customer || '';
const subscriptionId = subscription.id || '';
const newPriceId = subscription.items?.data?.[0]?.price?.id || '';
const oldPriceId = previousAttributes.items?.data?.[0]?.price?.id || '';

const tierRank = { free: 0, starter: 1, pro: 2, scale: 3 };

const priceToTier = (priceId) => {
  if (!priceId) return 'free';
  if (priceId.includes('scale')) return 'scale';
  if (priceId.includes('pro')) return 'pro';
  if (priceId.includes('starter')) return 'starter';
  const map = {
    'price_free': 'free',
    'price_starter': 'starter',
    'price_pro': 'pro',
    'price_scale': 'scale'
  };
  return map[priceId] || 'free';
};

const oldTier = priceToTier(oldPriceId);
const newTier = priceToTier(newPriceId);
const isDowngrade = tierRank[newTier] < tierRank[oldTier];

const featureFlags = {
  free: { launchpad_access: true, nova_os_access: false, ai_tools_limit: 3, automation_systems: 0, priority_support: false, white_label: false },
  starter: { launchpad_access: true, nova_os_access: false, ai_tools_limit: 10, automation_systems: 2, priority_support: false, white_label: false },
  pro: { launchpad_access: true, nova_os_access: true, ai_tools_limit: 10, automation_systems: 6, priority_support: true, white_label: false },
  scale: { launchpad_access: true, nova_os_access: true, ai_tools_limit: 10, automation_systems: 6, priority_support: true, white_label: true }
};

const oldFlags = featureFlags[oldTier] || featureFlags['free'];
const newFlags = featureFlags[newTier] || featureFlags['free'];

// Features being REVOKED
const revokedFeatures = [];
if (oldFlags.nova_os_access && !newFlags.nova_os_access) revokedFeatures.push('Nova OS Access');
if (oldFlags.priority_support && !newFlags.priority_support) revokedFeatures.push('Priority Support');
if (oldFlags.white_label && !newFlags.white_label) revokedFeatures.push('White Label');
if (oldFlags.automation_systems > newFlags.automation_systems) revokedFeatures.push(`Reduced to ${newFlags.automation_systems} Automation Systems`);
if (oldFlags.ai_tools_limit > newFlags.ai_tools_limit) revokedFeatures.push(`Reduced to ${newFlags.ai_tools_limit} AI Tools`);

const planDisplayNames = { free: 'Free', starter: 'Starter ($49/mo)', pro: 'Pro ($149/mo)', scale: 'Scale ($299/mo)' };

return [{ json: {
  customerId,
  subscriptionId,
  oldPriceId,
  newPriceId,
  oldTier,
  newTier,
  isDowngrade,
  newFlags,
  revokedFeatures,
  oldPlanDisplayName: planDisplayNames[oldTier] || oldTier,
  newPlanDisplayName: planDisplayNames[newTier] || newTier,
  updatedAt: new Date().toISOString(),
  rawPayload: JSON.stringify(body)
} }];

const users = $input.first().json;
const user = Array.isArray(users) ? users[0] : users;
const parsed = $('Parse Downgrade Payload').first().json;
return [{ json: { ...parsed, email: user?.email || '', firstName: user?.first_name || 'there' } }];

